const crypto = require('crypto');
const SECRET = $env.JARVIS_WEBHOOK_SECRET; // configure in n8n env/credentials
const headers = $input.first().json.headers || {};
const ts = headers['x-jarvis-timestamp'];
const sig = headers['x-jarvis-signature'] || '';
const raw = $input.first().binary?.data
  ? Buffer.from($input.first().binary.data.data, 'base64').toString()
  : JSON.stringify($input.first().json.body || {});

let valid = false;
if (SECRET && ts && sig) {
  const fresh = Math.abs(Date.now() / 1000 - Number(ts)) < 300; // 5 min window
  const expected = crypto.createHmac('sha256', SECRET).update(`${ts}.${raw}`).digest('hex');
  const a = Buffer.from(expected, 'hex');
  const b = Buffer.from(sig, 'hex');
  valid = fresh && a.length === b.length && crypto.timingSafeEqual(a, b);
}
// Anti-replay: dedupe por request-id en staticData (ventana 5 min).
const reqId = headers['x-jarvis-request-id'];
if (valid && reqId) {
  const store = $getWorkflowStaticData('global');
  const now = Date.now() / 1000;
  store.seen = store.seen || {};
  for (const k of Object.keys(store.seen)) { if (now - store.seen[k] > 300) delete store.seen[k]; }
  if (store.seen[reqId]) { valid = false; } else { store.seen[reqId] = now; }
}
return [{ json: { valid, payload: JSON.parse(raw || '{}') } }];
